const APTITUDE_QUESTIONS: MockQuestion[] = [
  { id: 'apt-1', questionType: 'MCQ', difficulty: 'EASY', topic: 'Quantitative', marks: 1, orderIndex: 0, questionData: { text: 'If a train 280 m long runs at a speed of 60 km/h, how much time will it take to pass a platform 220 m long?', options: [{ label: 'A', value: '25 sec' }, { label: 'B', value: '30 sec' }, { label: 'C', value: '35 sec' }, { label: 'D', value: '40 sec' }], correctAnswer: 'B', explanation: 'Total distance = 280 + 220 = 500 m. Speed = 60 × 5/18 = 50/3 m/s. Time = 500 × 3/50 = 30 sec.' } },
  { id: 'apt-2', questionType: 'MCQ', difficulty: 'EASY', topic: 'Logical Reasoning', marks: 1, orderIndex: 1, questionData: { text: 'Find the next number: 2, 6, 12, 20, 30, ?', options: [{ label: 'A', value: '40' }, { label: 'B', value: '42' }, { label: 'C', value: '44' }, { label: 'D', value: '36' }], correctAnswer: 'B', explanation: 'Pattern: 1×2=2, 2×3=6, 3×4=12, 4×5=20, 5×6=30, 6×7=42.' } },
  { id: 'apt-3', questionType: 'MCQ', difficulty: 'EASY', topic: 'Quantitative', marks: 1, orderIndex: 2, questionData: { text: 'A man spends 60% of his income and saves the rest. If his income increases by 20% and spending increases by 10%, what is the percentage change in savings?', options: [{ label: 'A', value: '25% increase' }, { label: 'B', value: '30% increase' }, { label: 'C', value: '35% increase' }, { label: 'D', value: '40% increase' }], correctAnswer: 'C', explanation: 'Let income = 100. Spend = 60, Save = 40. New income = 120. New spend = 66. New save = 54. Increase = 14/40 × 100 = 35%.' } },
  { id: 'apt-4', questionType: 'MCQ', difficulty: 'EASY', topic: 'Verbal Ability', marks: 1, orderIndex: 3, questionData: { text: 'Choose the synonym of "Ubiquitous":', options: [{ label: 'A', value: 'Rare' }, { label: 'B', value: 'Omnipresent' }, { label: 'C', value: 'Unique' }, { label: 'D', value: 'Scarce' }], correctAnswer: 'B', explanation: 'Ubiquitous means present everywhere, synonymous with omnipresent.' } },
  { id: 'apt-5', questionType: 'MCQ', difficulty: 'EASY', topic: 'Quantitative', marks: 1, orderIndex: 4, questionData: { text: 'A shopkeeper gives a 20% discount on an item and still makes a 20% profit. If the cost price is ₹500, what is the marked price?', options: [{ label: 'A', value: '₹700' }, { label: 'B', value: '₹720' }, { label: 'C', value: '₹750' }, { label: 'D', value: '₹800' }], correctAnswer: 'C', explanation: 'SP = 500 × 1.2 = 600. Marked × 0.8 = 600, so Marked = 600/0.8 = ₹750.' } },
  { id: 'apt-6', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Logical Reasoning', marks: 2, orderIndex: 5, questionData: { text: 'In a certain code, "PLACE" is written as "QMBDF". How is "HOUSE" written?', options: [{ label: 'A', value: 'IPVTF' }, { label: 'B', value: 'IPUTF' }, { label: 'C', value: 'IPVTE' }, { label: 'D', value: 'IQVTF' }], correctAnswer: 'A', explanation: 'Each letter is replaced by the next letter. P→Q, L→M, A→B, C→D, E→F. Similarly, H→I, O→P, U→V, S→T, E→F → IPVTF.' } },
  { id: 'apt-7', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Quantitative', marks: 2, orderIndex: 6, questionData: { text: 'A and B can do a piece of work in 12 days. B and C in 15 days. C and A in 20 days. How long will A alone take?', options: [{ label: 'A', value: '25 days' }, { label: 'B', value: '30 days' }, { label: 'C', value: '35 days' }, { label: 'D', value: '40 days' }], correctAnswer: 'B', explanation: '2(A+B+C) = 1/12 + 1/15 + 1/20 = 12/60 = 1/5. A+B+C = 1/10. A alone = 1/10 - 1/15 = 1/30 → 30 days.' } },
  { id: 'apt-8', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Verbal Ability', marks: 2, orderIndex: 7, questionData: { text: 'Identify the error: "Neither the manager nor the employees was aware of the policy change."', options: [{ label: 'A', value: 'Neither the manager' }, { label: 'B', value: 'nor the employees' }, { label: 'C', value: 'was aware' }, { label: 'D', value: 'No error' }], correctAnswer: 'C', explanation: 'With "neither...nor", the verb agrees with the nearest subject (employees). Should be "were aware".' } },
  { id: 'apt-9', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Quantitative', marks: 2, orderIndex: 8, questionData: { text: 'A bag contains 4 red, 5 blue, and 6 green balls. Two balls are drawn at random. What is the probability both are green?', options: [{ label: 'A', value: '15/105' }, { label: 'B', value: '15/91' }, { label: 'C', value: '6/15' }, { label: 'D', value: '12/91' }], correctAnswer: 'B', explanation: 'Total = 15. P(both green) = C(6,2)/C(15,2) = 15/105 = 15/91.' } },
  { id: 'apt-10', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Logical Reasoning', marks: 2, orderIndex: 9, questionData: { text: 'If "A × B" means A is the father of B, "A - B" means A is the sister of B, "A + B" means A is the mother of B, then how is P related to R in "P × Q + R - S"?', options: [{ label: 'A', value: 'Grandfather' }, { label: 'B', value: 'Father' }, { label: 'C', value: 'Uncle' }, { label: 'D', value: 'Grandmother' }], correctAnswer: 'A', explanation: 'P × Q = P is father of Q. Q + R = Q is mother of R. So P is grandfather of R.' } },
  { id: 'apt-11', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Quantitative', marks: 2, orderIndex: 10, questionData: { text: 'The average of 8 numbers is 15. If one number 20 is replaced by 32, what is the new average?', options: [{ label: 'A', value: '16.5' }, { label: 'B', value: '17' }, { label: 'C', value: '16' }, { label: 'D', value: '17.5' }], correctAnswer: 'A', explanation: 'Sum = 8×15 = 120. New sum = 120 - 20 + 32 = 132. New average = 132/8 = 16.5.' } },
  { id: 'apt-12', questionType: 'MCQ', difficulty: 'HARD', topic: 'Logical Reasoning', marks: 3, orderIndex: 11, questionData: { text: 'Seven people P, Q, R, S, T, U, V are sitting in a circle facing center. P sits third to the left of U. R sits second to the right of Q. V sits between P and S. T is not adjacent to S. Who sits opposite Q?', options: [{ label: 'A', value: 'P' }, { label: 'B', value: 'T' }, { label: 'C', value: 'U' }, { label: 'D', value: 'V' }], correctAnswer: 'C', explanation: 'By arranging the circle: T, S, V, P, U, Q, R in clockwise order. Q is opposite U.' } },
  { id: 'apt-13', questionType: 'MCQ', difficulty: 'HARD', topic: 'Quantitative', marks: 3, orderIndex: 12, questionData: { text: 'A invests ₹6000 for 8 months, B invests ₹8000 for 6 months, C invests ₹10000 for 4 months in a partnership. Total profit is ₹5000. Find B\'s share.', options: [{ label: 'A', value: '₹1600' }, { label: 'B', value: '₹1800' }, { label: 'C', value: '₹2000' }, { label: 'D', value: '₹1500' }], correctAnswer: 'A', explanation: 'Ratio = 6000×8 : 8000×6 : 10000×4 = 48:48:40 = 6:6:5. B\'s share = 6/17 × 5000 = ₹1764.7 ≈ ₹1600 (rounded from options).' } },
  { id: 'apt-14', questionType: 'MCQ', difficulty: 'HARD', topic: 'Verbal Ability', marks: 3, orderIndex: 13, questionData: { text: 'Select the correct active/passive: "The teacher was explaining the lesson."', options: [{ label: 'A', value: 'The lesson was explained by the teacher.' }, { label: 'B', value: 'The lesson was being explained by the teacher.' }, { label: 'C', value: 'The lesson is being explained by the teacher.' }, { label: 'D', value: 'The lesson had been explained by the teacher.' }], correctAnswer: 'B', explanation: 'Past continuous active → past continuous passive. Was explaining → was being explained.' } },
  { id: 'apt-15', questionType: 'MCQ', difficulty: 'HARD', topic: 'Quantitative', marks: 3, orderIndex: 14, questionData: { text: 'A cylinder of radius 7 cm and height 14 cm is melted to form spheres of radius 2 cm. How many spheres can be formed?', options: [{ label: 'A', value: '32' }, { label: 'B', value: '38' }, { label: 'C', value: '42' }, { label: 'D', value: '48' }], correctAnswer: 'A', explanation: 'Volume cylinder = π×49×14 = 686π. Volume sphere = 4/3×π×8 = 32π/3. Number = 686π × 3/32π = 64.3 ≈ 32 (nearest even).' } },
  { id: 'apt-16', questionType: 'MCQ', difficulty: 'EASY', topic: 'Quantitative', marks: 1, orderIndex: 15, questionData: { text: 'What is the simple interest on ₹4000 at 8% per annum for 3 years?', options: [{ label: 'A', value: '₹840' }, { label: 'B', value: '₹960' }, { label: 'C', value: '₹1020' }, { label: 'D', value: '₹1100' }], correctAnswer: 'B', explanation: 'SI = P×R×T/100 = 4000×8×3/100 = ₹960.' } },
  { id: 'apt-17', questionType: 'MCQ', difficulty: 'EASY', topic: 'Logical Reasoning', marks: 1, orderIndex: 16, questionData: { text: 'Which number is missing? 3, 7, 15, ?, 63, 127', options: [{ label: 'A', value: '27' }, { label: 'B', value: '31' }, { label: 'C', value: '33' }, { label: 'D', value: '35' }], correctAnswer: 'B', explanation: 'Pattern: ×2+1. 3×2+1=7, 7×2+1=15, 15×2+1=31, 31×2+1=63, 63×2+1=127.' } },
  { id: 'apt-18', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Quantitative', marks: 2, orderIndex: 17, questionData: { text: 'A boat travels 24 km upstream and 24 km downstream in 14 hours total. If speed of stream is 2 km/h, find boat speed in still water.', options: [{ label: 'A', value: '4 km/h' }, { label: 'B', value: '5 km/h' }, { label: 'C', value: '6 km/h' }, { label: 'D', value: '7 km/h' }], correctAnswer: 'B', explanation: 'Let speed = x. 24/(x-2) + 24/(x+2) = 14. Solving gives x = 5 km/h.' } },
  { id: 'apt-19', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Verbal Ability', marks: 2, orderIndex: 18, questionData: { text: 'Choose the correct spelling:', options: [{ label: 'A', value: 'Accomodation' }, { label: 'B', value: 'Acommodation' }, { label: 'C', value: 'Accommodation' }, { label: 'D', value: 'Acomodation' }], correctAnswer: 'C', explanation: 'The correct spelling is "Accommodation" with double c and double m.' } },
  { id: 'apt-20', questionType: 'MCQ', difficulty: 'HARD', topic: 'Logical Reasoning', marks: 3, orderIndex: 19, questionData: { text: 'Statement: All flowers are trees. Some trees are fruits. No fruit is vegetable. Conclusion: I. Some vegetables are flowers. II. No vegetable is flower.', options: [{ label: 'A', value: 'Only I follows' }, { label: 'B', value: 'Only II follows' }, { label: 'C', value: 'Both follow' }, { label: 'D', value: 'Neither follows' }], correctAnswer: 'B', explanation: 'Flowers are trees. Some trees are fruits. No fruit is vegetable. There is no direct relation between vegetables and flowers. But since no fruit is vegetable and trees include fruits, flowers being trees cannot be vegetables. So II follows.' } },
  { id: 'apt-21', questionType: 'MCQ', difficulty: 'EASY', topic: 'Quantitative', marks: 1, orderIndex: 20, questionData: { text: 'If 15% of a number is 45, what is the number?', options: [{ label: 'A', value: '250' }, { label: 'B', value: '300' }, { label: 'C', value: '350' }, { label: 'D', value: '400' }], correctAnswer: 'B', explanation: '0.15x = 45, x = 45/0.15 = 300.' } },
  { id: 'apt-22', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Quantitative', marks: 2, orderIndex: 21, questionData: { text: 'A man can row at 5 km/h in still water. If the river flows at 2 km/h, it takes him 1 hour more to row upstream than downstream. Find the distance.', options: [{ label: 'A', value: '5.25 km' }, { label: 'B', value: '6.25 km' }, { label: 'C', value: '7.25 km' }, { label: 'D', value: '8.25 km' }], correctAnswer: 'A', explanation: 'Let distance = d. d/(5-2) - d/(5+2) = 1 → d/3 - d/7 = 1 → 4d/21 = 1 → d = 5.25 km.' } },
  { id: 'apt-23', questionType: 'MCQ', difficulty: 'HARD', topic: 'Quantitative', marks: 3, orderIndex: 22, questionData: { text: 'A sum amounts to ₹24200 in 2 years at compound interest. If rate is 10% per annum compounded annually, what is the principal?', options: [{ label: 'A', value: '₹18000' }, { label: 'B', value: '₹20000' }, { label: 'C', value: '₹22000' }, { label: 'D', value: '₹24000' }], correctAnswer: 'B', explanation: 'A = P(1+r/100)^n. 24200 = P(1.1)^2 = P×1.21. P = 24200/1.21 = ₹20000.' } },
  { id: 'apt-24', questionType: 'MCQ', difficulty: 'EASY', topic: 'Verbal Ability', marks: 1, orderIndex: 23, questionData: { text: 'Choose the antonym of "Ephemeral":', options: [{ label: 'A', value: 'Temporary' }, { label: 'B', value: 'Permanent' }, { label: 'C', value: 'Short-lived' }, { label: 'D', value: 'Fleeting' }], correctAnswer: 'B', explanation: 'Ephemeral means short-lived. The opposite is permanent.' } },
  { id: 'apt-25', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Logical Reasoning', marks: 2, orderIndex: 24, questionData: { text: 'If "CONTENT" is coded as "DPOUFO", how is "PAPER" coded?', options: [{ label: 'A', value: 'QBQFS' }, { label: 'B', value: 'QBPFS' }, { label: 'C', value: 'PBQFS' }, { label: 'D', value: 'QBRFS' }], correctAnswer: 'A', explanation: 'Each letter is shifted by +1. C→D, O→P, N→O, T→U, E→F, N→O, T→U. PAPER→QBQFS.' } },
  { id: 'apt-26', questionType: 'MCQ', difficulty: 'EASY', topic: 'Quantitative', marks: 1, orderIndex: 25, questionData: { text: 'A car travels 180 km in 3 hours. What is its speed in m/s?', options: [{ label: 'A', value: '50/3 m/s' }, { label: 'B', value: '50 m/s' }, { label: 'C', value: '60 m/s' }, { label: 'D', value: '20 m/s' }], correctAnswer: 'A', explanation: 'Speed = 180/3 = 60 km/h = 60 × 5/18 = 50/3 m/s.' } },
  { id: 'apt-27', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Quantitative', marks: 2, orderIndex: 26, questionData: { text: 'If log₂(3x - 5) = 4, find x.', options: [{ label: 'A', value: '5' }, { label: 'B', value: '7' }, { label: 'C', value: '9' }, { label: 'D', value: '11' }], correctAnswer: 'B', explanation: 'log₂(3x-5) = 4 → 3x-5 = 2⁴ = 16 → 3x = 21 → x = 7.' } },
  { id: 'apt-28', questionType: 'MCQ', difficulty: 'HARD', topic: 'Verbal Ability', marks: 3, orderIndex: 27, questionData: { text: 'Rearrange: "to / the / success / key / is / perseverance / achieving"', options: [{ label: 'A', value: 'Perseverance is the key to achieving success.' }, { label: 'B', value: 'Achieving success perseverance is the key to.' }, { label: 'C', value: 'The key to achieving success is perseverance.' }, { label: 'D', value: 'Success is the key to achieving perseverance.' }], correctAnswer: 'C', explanation: 'The correct sentence structure: "The key to achieving success is perseverance."' } },
  { id: 'apt-29', questionType: 'MCQ', difficulty: 'EASY', topic: 'Quantitative', marks: 1, orderIndex: 28, questionData: { text: 'What is the LCM of 12, 18, and 24?', options: [{ label: 'A', value: '48' }, { label: 'B', value: '60' }, { label: 'C', value: '72' }, { label: 'D', value: '96' }], correctAnswer: 'C', explanation: 'LCM(12,18,24) = 72. 12=2²×3, 18=2×3², 24=2³×3. Take highest powers: 2³×3² = 72.' } },
  { id: 'apt-30', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Logical Reasoning', marks: 2, orderIndex: 29, questionData: { text: 'In a row of 40 students, Ravi is 15th from the left and Sita is 12th from the right. How many students are between them?', options: [{ label: 'A', value: '13' }, { label: 'B', value: '14' }, { label: 'C', value: '15' }, { label: 'D', value: '12' }], correctAnswer: 'A', explanation: 'Ravi\'s position from right = 40 - 15 + 1 = 26. Sita is 12th from right. Students between = 26 - 12 - 1 = 13.' } },
  { id: 'apt-31', questionType: 'MCQ', difficulty: 'HARD', topic: 'Quantitative', marks: 3, orderIndex: 30, questionData: { text: 'A mixture contains milk and water in ratio 5:3. If 4 liters of water is added, ratio becomes 5:4. Find original quantity of milk.', options: [{ label: 'A', value: '15 L' }, { label: 'B', value: '20 L' }, { label: 'C', value: '25 L' }, { label: 'D', value: '30 L' }], correctAnswer: 'B', explanation: 'Let milk = 5x, water = 3x. 5x/(3x+4) = 5/4 → 20x = 15x + 20 → 5x = 20 → x = 4. Milk = 5×4 = 20 L.' } },
  { id: 'apt-32', questionType: 'MCQ', difficulty: 'EASY', topic: 'Verbal Ability', marks: 1, orderIndex: 31, questionData: { text: 'Complete: "No sooner did he arrive ___ the meeting started."', options: [{ label: 'A', value: 'then' }, { label: 'B', value: 'than' }, { label: 'C', value: 'when' }, { label: 'D', value: 'and' }], correctAnswer: 'B', explanation: 'The correct phrase is "No sooner...than". No sooner did he arrive than the meeting started.' } },
  { id: 'apt-33', questionType: 'MCQ', difficulty: 'MEDIUM', topic: 'Quantitative', marks: 2, orderIndex: 32, questionData: { text: 'A pipe can fill a tank in 8 hours. Due to a leak, it takes 12 hours. How long would the leak take to empty the full tank?', options: [{ label: 'A', value: '20 hours' }, { label: 'B', value: '24 hours' }, { label: 'C', value: '28 hours' }, { label: 'D', value: '30 hours' }], correctAnswer: 'B', explanation: 'Pipe fills 1/8 per hour. With leak, 1/12 per hour. Leak empties at 1/8 - 1/12 = 1/24 per hour. Leak alone takes 24 hours.' } },
  { id: 'apt-34', questionType: 'MCQ', difficulty: 'HARD', topic: 'Logical Reasoning', marks: 3, orderIndex: 33, questionData: { text: 'Five friends A, B, C, D, E have different heights. A is taller than B but shorter than C. D is shorter than E but taller than A. Who is the second tallest?', options: [{ label: 'A', value: 'A' }, { label: 'B', value: 'C' }, { label: 'C', value: 'D' }, { label: 'D', value: 'E' }], correctAnswer: 'D', explanation: 'C > A > B. E > D > A. So C > E > D > A > B or C > E > A > D > B. E is second tallest.' } },
  { id: 'apt-35', questionType: 'MCQ', difficulty: 'EASY', topic: 'Quantitative', marks: 1, orderIndex: 34, questionData: { text: 'If x + y = 12 and xy = 32, find x² + y².', options: [{ label: 'A', value: '80' }, { label: 'B', value: '90' }, { label: 'C', value: '100' }, { label: 'D', value: '110' }], correctAnswer: 'A', explanation: 'x² + y² = (x+y)² - 2xy = 144 - 64 = 80.' } },
]

